public class Planet {
    private double radius; // radius of the planet in kilometers

    public Planet(double radius) {
        this.radius = radius;
    }

    public double calculateSurfaceArea() {
        return 4 * Math.PI * Math.pow(radius, 2);
    }

    public static void main(String[] args) {
        Planet earth = new Planet(6371); // Earth's radius in kilometers
        System.out.println("Surface Area of Earth: " + earth.calculateSurfaceArea() + " square kilometers");
    }
}
