function calculateCosmicVibrations(input) {
    // Convert the input string into an array of characters
    const characters = input.split('');
    // Initialize an empty array to hold the vibration values
    const vibrations = [];

    // Iterate over each character in the array
    for (let char of characters) {
        // Calculate the vibration value based on the character's ASCII code
        const vibrationValue = char.charCodeAt(0) % 10; // Using modulo 10 to get a single digit
        vibrations.push(vibrationValue); // Add the vibration value to the array
    }

    return vibrations; // Return the array of vibration values
}
